1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const key = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	export function nextGeneration(liveCells: Cell[]): Cell[] {
15	  const alive = new Set(liveCells.map(key));
16	  const liveNeighborCount = (cell: Cell): number =>
17	    neighborsOf(cell).filter((n) => alive.has(key(n))).length;
18	  return liveCells.filter((cell) => {
19	    const count = liveNeighborCount(cell);
20	    return count === 2 || count === 3;
21	  });
22	}
