const survives = (liveNeighbors: number): boolean =>
  liveNeighbors === 2 || liveNeighbors === 3;

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const alive = new Set(liveCells.map(key));
  const liveNeighborCount = (cell: Cell): number =>
    neighborsOf(cell).filter((n) => alive.has(key(n))).length;
  return liveCells.filter((cell) => survives(liveNeighborCount(cell)));
}
